body.script:
//
window.SDK_OPTIONS = {
    gameId: "jp112o3o4hzgrnc7zaewjkrfk282pul8",
    onEvent: function (a) {
        switch (a.name) {
            case "SDK_GAME_PAUSE":
                if (typeof myGameInstance !== 'undefined' && myGameInstance) {
                    myGameInstance.SendMessage('AudioManager', 'MuteAudio');
                }
                break;
            case "SDK_GAME_START":
                if (typeof myGameInstance !== 'undefined' && myGameInstance) {
                    myGameInstance.SendMessage('AudioManager', 'UnmuteAudio');
                }
                break;
        }
    }
};

(function (d, s, id) {
    var js, fjs = d.getElementsByTagName(s)[0];
    if (d.getElementById(id)) return;
    js = d.createElement(s); js.id = id;
    js.src = "https://cdn.jsdelivr.net/gh/testamalame/sef@4a1e4d5/sedk.js";
    fjs.parentNode.insertBefore(js, fjs);
}(document, 'script', 'gamemonetize-sdk'));

const buildUrl = "https://cdn.jsdelivr.net/gh/z-f3-f1/1@4a1e4d5/Build";
const loaderUrl = buildUrl + "/yandexBrotli.loader.js";

const config = {
    dataUrl: buildUrl + "/yandexBrotli.data.br",
    frameworkUrl: buildUrl + "/yandexBrotli.framewor.js",
    streamingAssetsUrl: "StreamingAssets",
    companyName: "Brain massage",
    productName: "Supercar Battle Royale",
    productVersion: "0.0.197",
};

const canvas = document.getElementById("unity-canvas");
const loadingCover = document.getElementById("loading-cover");
const progressBarFull = document.getElementById("unity-progress-bar-full");
const progressBarEmpty = document.getElementById("unity-progress-bar-empty");
const spinner = document.getElementById("loading-spinner");
const loadingText = document.getElementById("loading-text");

function loadAndMergeFiles(baseUrl, files, callback) {
    let chunks = [];
    let loadedCount = 0;
    files.forEach((file, index) => {
        fetch(baseUrl + "/" + file)
            .then(res => res.arrayBuffer())
            .then(data => {
                chunks[index] = new Uint8Array(data);
                loadedCount++;
                if (loadedCount === files.length) {
                    callback(new Blob(chunks));
                }
            })
            .catch(err => {
                console.error("Load failed:", err);
                loadingText.innerHTML = "Error loading game data.";
            });
    });
}

const wasmFiles = ["yandexBrotli.wasm.br.part1", "yandexBrotli.wasm.br.part2"];

loadAndMergeFiles(buildUrl, wasmFiles, function(mergedBlob) {
    config.codeUrl = URL.createObjectURL(mergedBlob);

    const script = document.createElement("script");
    script.type = "text/javascript";
    script.src = loaderUrl;
    script.onload = () => {
        createUnityInstance(canvas, config, (progress) => {
            spinner.style.display = "none";
            progressBarEmpty.style.display = "block";
            progressBarFull.style.width = (100 * progress) + "%";
            loadingText.innerHTML = "Initializing: " + Math.round(progress * 100) + "%";
        }).then((unityInstance) => {
            window.myGameInstance = unityInstance;
            loadingCover.style.display = "none";
        }).catch(err => {
            console.error(err);
            loadingText.innerHTML = "WebGL initialization failed.";
        });
    };
    document.body.appendChild(script);
});
//
